import { unstable_cache } from "next/cache";
import { revalidateTag } from "next/cache";
import { getAllProducts } from "@/lib/db";

/* ------------------------------------------------------------------ */
/*  Cached product fetcher                                             */
/*  Tagged with "products" so a single revalidateTag call busts the    */
/*  cache across every view that uses the same tag (catalog, widget,   */
/*  dashboard, etc.). This avoids re-querying on every page load.      */
/* ------------------------------------------------------------------ */
interface Product {
  id: number;
  name: string;
  price: number;
}

interface CachedResult {
  products: Product[];
  fetchedAt: number;
}

const getCachedProducts = unstable_cache<() => Promise<CachedResult>>(
  async () => {
    const products = await getAllProducts();
    return { products, fetchedAt: Date.now() };
  },
  ["products-catalog-data"],
  { tags: ["products"] }
);

/* ------------------------------------------------------------------ */
/*  Page                                                                */
/* ------------------------------------------------------------------ */
export default async function AdminProductsPage() {
  const { products, fetchedAt } = await getCachedProducts();

  // ── Inline Server Action ────────────────────────────────────────
  // Regular HTML form submission — no client JavaScript required.
  // The cache is invalidated in-band so the re-rendered page picks up
  // fresh data immediately, while other concurrent views (dashboards,
  // widgets) catch up on their next request.
  async function syncCatalog(formData: FormData) {
    "use server";
    revalidateTag("products");
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-5xl mx-auto px-6 py-10">
        {/* ── Header ───────────────────────────────────────────── */}
        <div className="flex items-start justify-between mb-8">
          <div>
            <h1 className="text-3xl font-bold tracking-tight text-gray-900">
              Product Catalog
            </h1>
            <p className="text-sm text-gray-500 mt-1.5">
              Last cached:{" "}
              <time
                dateTime={new Date(fetchedAt).toISOString()}
                className="font-mono text-gray-600"
              >
                {new Date(fetchedAt).toLocaleString()}
              </time>
            </p>
          </div>

          {/* ── Sync form — regular HTML form, no JS needed ──── */}
          <form action={syncCatalog}>
            <button
              type="submit"
              className="inline-flex items-center gap-2 rounded-lg bg-blue-600
                         px-5 py-2.5 text-sm font-medium text-white shadow-sm
                         hover:bg-blue-700 focus-visible:outline focus-visible:outline-2
                         focus-visible:outline-offset-2 focus-visible:outline-blue-600
                         transition-colors"
            >
              <svg
                className="h-4 w-4"
                fill="none"
                viewBox="0 0 24 24"
                strokeWidth={2}
                stroke="currentColor"
                aria-hidden="true"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  d="M16.023 9.348h4.992v-.001M2.985 19.644v-4.992m0 0h4.992m-4.993 0l3.181 3.183a8.25 8.25 0 0013.803-3.7M4.031 9.865a8.25 8.25 0 0113.803-3.7l3.181 3.182"
                />
              </svg>
              Sync latest catalog
            </button>
          </form>
        </div>

        {/* ── Product table ─────────────────────────────────────── */}
        <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm">
          <table className="w-full">
            <thead>
              <tr className="bg-gray-50 text-left text-xs font-semibold uppercase tracking-wider text-gray-500">
                <th className="px-5 py-3.5">SKU</th>
                <th className="px-5 py-3.5">Name</th>
                <th className="px-5 py-3.5 text-right">Price</th>
              </tr>
            </thead>
            <tbody>
              {products.length === 0 ? (
                <tr>
                  <td
                    colSpan={3}
                    className="px-5 py-12 text-center text-sm text-gray-400"
                  >
                    No products found.
                  </td>
                </tr>
              ) : (
                products.map((product) => (
                  <tr
                    key={product.id}
                    className="border-t border-gray-100 transition-colors hover:bg-gray-50/80"
                  >
                    <td className="px-5 py-3.5 text-sm text-gray-500">
                      #{String(product.id).padStart(4, "0")}
                    </td>
                    <td className="px-5 py-3.5 text-sm font-medium text-gray-900">
                      {product.name}
                    </td>
                    <td className="px-5 py-3.5 text-right text-sm font-mono tabular-nums text-gray-700">
                      ${product.price.toFixed(2)}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* ── Footer note ──────────────────────────────────────── */}
        <p className="mt-4 text-xs text-gray-400 leading-relaxed">
          Data is cached under the <code className="text-gray-500">products</code>{" "}
          cache tag. Clicking &ldquo;Sync latest catalog&rdquo; invalidates the
          tag — the next request to <em>any</em> view that shares the same tag
          will fetch fresh data. You can continue working immediately while the
          cache is refreshed in the background.
        </p>
      </div>
    </div>
  );
}

